var CountComponent = function(props) {
  var count = props.count;
  return React.createElement('div', null,
    React.createElement('p', null, 'Count: ' + count),
    React.createElement('button', { onClick: function() { count--; } }, '-'),
    React.createElement('button', { onClick: function() { count++; } }, '+')
  );
};
